"use strict";var e=require("../utils/http.js");const t={loginByUserId:t=>e.request({url:`/admin/user/${t}`,method:"GET",showLoading:!0}),listSimple:()=>e.request({url:"/admin/user/list",method:"GET",showLoading:!1}),updateProfile:t=>e.request({url:"/admin/user/update",method:"POST",data:t,needAuth:!1}),updateInterests:(t,s)=>e.request({url:"/admin/user/interests",method:"POST",data:{id:t,interests:s},needAuth:!1}),getStats:t=>e.request({url:"/user/stats",method:"GET",data:t?{userId:t}:{},showLoading:!1}),getProfile:t=>e.request({url:"/user/profile",method:"GET",data:{userId:t},showLoading:!0}),checkIn:t=>e.request({url:"/user/checkin",method:"POST",data:{userId:t},showLoading:!0,needAuth:!0}),getFollowers:(t,s=1,r=20)=>e.request({url:"/user/followers",method:"GET",data:{userId:t,pageNum:s,pageSize:r},showLoading:!1}),getFollowing:(t,s=1,r=20)=>e.request({url:"/user/following",method:"GET",data:{userId:t,pageNum:s,pageSize:r},showLoading:!1}),toggleFollow:(t,s)=>e.request({url:"/user/follow",method:"POST",data:{userId:t,targetUserId:s},showLoading:!0,needAuth:!0})};exports.userApi=t;
